import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    conn = psycopg2.connect(database="your_db", user="your_user", password="your_password", host="your_host", port="your_port")
    cursor = conn.cursor()
    
    query_parts = ["SELECT * FROM users"]
    params = []
    
    if username:
        query_parts.append("username = %s")
        params.append(username)
    if email:
        query_parts.append("email = %s")
        params.append(email)
    if role:
        query_parts.append("role = %s")
        params.append(role)
    if status:
        query_parts.append("status = %s")
        params.append(status)
    
    if len(params) > 0:
        query_parts.insert(1, "WHERE")
    
    query = " ".join(query_parts)
    
    cursor.execute(query, params)
    results = cursor.fetchall()
    
    cursor.close()
    conn.close()
    
    return results